   1→/**
   2→ * Sequant Dashboard Server
   3→ *
   4→ * A lightweight web dashboard for visualizing workflow state using:
   5→ * - Hono: Fast, lightweight web framework
   6→ * - htmx: HTML-first interactivity
   7→ * - Pico CSS: Classless styling
   8→ * - SSE: Server-sent events for live updates
   9→ *
  10→ * @example
  11→ * ```typescript
  12→ * import { startDashboard } from './server';
  13→ * await startDashboard({ port: 3456, open: true });
  14→ * ```
  15→ */
  16→
  17→import { Hono } from "hono";
  18→import { streamSSE } from "hono/streaming";
  19→import { serve } from "@hono/node-server";
  20→import { watch } from "chokidar";
  21→import { StateManager } from "../src/lib/workflow/state-manager.js";
  22→import type {
  23→  IssueState,
  24→  IssueStatus,
  25→  LoopState,
  26→  Phase,
  27→  PhaseState,
  28→  PhaseStatus,
  29→  AcceptanceCriteria,
  30→  ACStatus,
  31→} from "../src/lib/workflow/state-schema.js";
  32→import { STATE_FILE_PATH } from "../src/lib/workflow/state-schema.js";
  33→import * as fs from "fs";
  34→
  35→export interface DashboardOptions {
  36→  /** Port to run the server on (default: 3456) */
  37→  port?: number;
  38→  /** Whether to open browser automatically (default: true) */
  39→  open?: boolean;
  40→  /** Custom state file path */
  41→  statePath?: string;
  42→  /** Enable verbose logging */
  43→  verbose?: boolean;
  44→}
  45→
  46→/** SSE client callback type */
  47→type SSECallback = (html: string) => void;
  48→
  49→/** Connected SSE clients */
  50→const clients: Set<SSECallback> = new Set();
  51→
  52→/**
  53→ * Escape HTML entities to prevent XSS
  54→ */
  55→function escapeHtml(text: string): string {
  56→  return text
  57→    .replace(/&/g, "&amp;")
  58→    .replace(/</g, "&lt;")
  59→    .replace(/>/g, "&gt;")
  60→    .replace(/"/g, "&quot;")
  61→    .replace(/'/g, "&#039;");
  62→}
  63→
  64→/**
  65→ * Get CSS class for issue status
  66→ */
  67→function getStatusClass(status: IssueStatus): string {
  68→  switch (status) {
  69→    case "in_progress":
  70→      return "primary";
  71→    case "waiting_for_qa_gate":
  72→      return "warning";
  73→    case "ready_for_merge":
  74→      return "success";
  75→    case "blocked":
  76→      return "warning";
  77→    case "merged":
  78→      return "success";
  79→    case "abandoned":
  80→      return "error";
  81→    default:
  82→      return "secondary";
  83→  }
  84→}
  85→
  86→/**
  87→ * Build tooltip text for a phase indicator
  88→ * Includes: status, duration (if completed), error (if failed)
  89→ */
  90→function buildPhaseTooltip(
  91→  phaseName: string,
  92→  phaseState: PhaseState | undefined,
  93→  loopState: LoopState | undefined,
  94→): string {
  95→  if (!phaseState) {
  96→    return `${phaseName}: Pending`;
  97→  }
  98→
  99→  const parts: string[] = [];
 100→
 101→  // Status text
 102→  const statusText =
 103→    phaseState.status.charAt(0).toUpperCase() +
 104→    phaseState.status.slice(1).replace(/_/g, " ");
 105→  parts.push(`${phaseName}: ${statusText}`);
 106→
 107→  // Duration (if we have both timestamps)
 108→  if (phaseState.startedAt && phaseState.completedAt) {
 109→    const duration = formatDuration(
 110→      phaseState.startedAt,
 111→      phaseState.completedAt,
 112→    );
 113→    parts.push(`Duration: ${duration}`);
 114→  }
 115→
 116→  // Loop iteration for loop phase
 117→  if (phaseName === "Loop" && loopState?.enabled) {
 118→    parts.push(`Iteration: ${loopState.iteration}/${loopState.maxIterations}`);
 119→  }
 120→
 121→  // Error message (if failed)
 122→  if (phaseState.status === "failed" && phaseState.error) {
 123→    // Truncate long errors for tooltip
 124→    const errorMsg =
 125→      phaseState.error.length > 100
 126→        ? phaseState.error.slice(0, 100) + "..."
 127→        : phaseState.error;
 128→    parts.push(`Error: ${errorMsg}`);
 129→  }
 130→
 131→  return parts.join(" | ");
 132→}
 133→
 134→/**
 135→ * Get phase indicator HTML
 136→ */
 137→function getPhaseIndicator(
 138→  phaseState: PhaseState | undefined,
 139→  options?: {
 140→    phaseName?: string;
 141→    isActive?: boolean;
 142→    loopState?: LoopState;
 143→  },
 144→): string {
 145→  const phaseName = options?.phaseName ?? "Phase";
 146→  const isActive = options?.isActive ?? false;
 147→  const tooltip = escapeHtml(
 148→    buildPhaseTooltip(phaseName, phaseState, options?.loopState),
 149→  );
 150→  const activeClass = isActive ? " active" : "";
 151→
 152→  if (!phaseState) {
 153→    return `<span class="phase-dot pending${activeClass}" title="${tooltip}">○</span>`;
 154→  }
 155→
 156→  switch (phaseState.status) {
 157→    case "pending":
 158→      return `<span class="phase-dot pending${activeClass}" title="${tooltip}">○</span>`;
 159→    case "in_progress":
 160→      return `<span class="phase-dot in-progress${activeClass}" title="${tooltip}">◐</span>`;
 161→    case "completed":
 162→      return `<span class="phase-dot completed${activeClass}" title="${tooltip}">●</span>`;
 163→    case "failed":
 164→      return `<span class="phase-dot failed${activeClass}" title="${tooltip}">✗</span>`;
 165→    case "skipped":
 166→      return `<span class="phase-dot skipped${activeClass}" title="${tooltip}">-</span>`;
 167→    default:
 168→      return `<span class="phase-dot${activeClass}" title="${tooltip}">?</span>`;
 169→  }
 170→}
 171→
 172→/**
 173→ * Format relative time
 174→ */
 175→function getRelativeTime(dateString: string): string {
 176→  const date = new Date(dateString);
 177→  const now = new Date();
 178→  const diffMs = now.getTime() - date.getTime();
 179→  const diffSec = Math.floor(diffMs / 1000);
 180→  const diffMin = Math.floor(diffSec / 60);
 181→  const diffHour = Math.floor(diffMin / 60);
 182→  const diffDay = Math.floor(diffHour / 24);
 183→
 184→  if (diffSec < 60) return "just now";
 185→  if (diffMin < 60) return `${diffMin}m ago`;
 186→  if (diffHour < 24) return `${diffHour}h ago`;
 187→  if (diffDay < 7) return `${diffDay}d ago`;
 188→  return date.toLocaleDateString();
 189→}
 190→
 191→/**
 192→ * Format duration between two timestamps
 193→ */
 194→function formatDuration(startedAt: string, completedAt: string): string {
 195→  const start = new Date(startedAt);
 196→  const end = new Date(completedAt);
 197→  const diffMs = end.getTime() - start.getTime();
 198→  const diffSec = Math.floor(diffMs / 1000);
 199→  const diffMin = Math.floor(diffSec / 60);
 200→  const diffHour = Math.floor(diffMin / 60);
 201→
 202→  if (diffSec < 60) return `${diffSec}s`;
 203→  if (diffMin < 60) return `${diffMin}m ${diffSec % 60}s`;
 204→  return `${diffHour}h ${diffMin % 60}m`;
 205→}
 206→
 207→/**
 208→ * Get status icon for acceptance criteria
 209→ */
 210→function getACStatusIcon(status: ACStatus): string {
 211→  switch (status) {
 212→    case "met":
 213→      return "✅";
 214→    case "not_met":
 215→      return "❌";
 216→    case "pending":
 217→      return "⏳";
 218→    case "blocked":
 219→      return "🚫";
 220→    default:
 221→      return "❓";
 222→  }
 223→}
 224→
 225→/**
 226→ * Render acceptance criteria section for an issue card
 227→ */
 228→function renderACSection(ac: AcceptanceCriteria | undefined): string {
 229→  if (!ac || ac.items.length === 0) {
 230→    return "";
 231→  }
 232→
 233→  const { summary } = ac;
 234→  const summaryText = `${summary.met}/${summary.total} met`;
 235→
 236→  // Determine badge class based on progress
 237→  let badgeClass = "ac-badge";
 238→  if (summary.met === summary.total) {
 239→    badgeClass += " complete";
 240→  } else if (summary.notMet > 0) {
 241→    badgeClass += " has-issues";
 242→  } else if (summary.blocked > 0) {
 243→    badgeClass += " blocked";
 244→  }
 245→
 246→  // Render individual AC items
 247→  const acItems = ac.items
 248→    .map((item) => {
 249→      const icon = getACStatusIcon(item.status);
 250→      const description = escapeHtml(
 251→        item.description.length > 60
 252→          ? item.description.slice(0, 57) + "..."
 253→          : item.description,
 254→      );
 255→      const notes = item.notes
 256→        ? `<span class="ac-notes" title="${escapeHtml(item.notes)}">(note)</span>`
 257→        : "";
 258→      return `<li class="ac-item ac-${item.status}">
 259→        <span class="ac-icon">${icon}</span>
 260→        <span class="ac-id">${escapeHtml(item.id)}:</span>
 261→        <span class="ac-desc">${description}</span>
 262→        ${notes}
 263→      </li>`;
 264→    })
 265→    .join("");
 266→
 267→  return `
 268→    <details class="ac-section">
 269→      <summary>
 270→        <span class="${badgeClass}">${summaryText}</span>
 271→        <span class="ac-label">Acceptance Criteria</span>
 272→      </summary>
 273→      <ul class="ac-list">
 274→        ${acItems}
 275→      </ul>
 276→    </details>
 277→  `;
 278→}
 279→
 280→/**
 281→ * Format tracking age (time since createdAt)
 282→ */
 283→function formatTrackingAge(createdAt: string): string {
 284→  const created = new Date(createdAt);
 285→  const now = new Date();
 286→  const diffMs = now.getTime() - created.getTime();
 287→  const diffHour = Math.floor(diffMs / (1000 * 60 * 60));
 288→  const diffDay = Math.floor(diffHour / 24);
 289→
 290→  if (diffHour < 1) return "Tracked for <1h";
 291→  if (diffHour < 24) return `Tracked for ${diffHour}h`;
 292→  if (diffDay === 1) return "Tracked for 1d";
 293→  return `Tracked for ${diffDay}d`;
 294→}
 295→
 296→/**
 297→ * Render a single issue card as HTML
 298→ */
 299→function renderIssueCard(issue: IssueState): string {
 300→  const phases: Phase[] = [
 301→    "spec",
 302→    "security-review",
 303→    "exec",
 304→    "testgen",
 305→    "test",
 306→    "verify",
 307→    "qa",
 308→    "loop",
 309→    "merger",
 310→  ];
 311→  const phaseLabels: Record<Phase, string> = {
 312→    spec: "Spec",
 313→    "security-review": "Sec",
 314→    exec: "Exec",
 315→    testgen: "TGen",
 316→    test: "Test",
 317→    verify: "Ver",
 318→    qa: "QA",
 319→    loop: "Loop",
 320→    merger: "Merge",
 321→  };
 322→
 323→  // Build phase indicators with enhanced tooltips (AC-A1, A2, A3, A4)
 324→  const phaseIndicators = phases
 325→    .map((p) => {
 326→      const phaseState = issue.phases[p] as PhaseState | undefined;
 327→      const isActive = issue.currentPhase === p;
 328→      const indicator = getPhaseIndicator(phaseState, {
 329→        phaseName: phaseLabels[p],
 330→        isActive,
 331→        loopState: p === "loop" ? issue.loop : undefined,
 332→      });
 333→      // Show loop iteration in label if loop is active (AC-A3)
 334→      let label = phaseLabels[p];
 335→      if (p === "loop" && issue.loop?.enabled && issue.loop.iteration > 0) {
 336→        label = `${issue.loop.iteration}/${issue.loop.maxIterations}`;
 337→      }
 338→      const activeClass = isActive ? " active" : "";
 339→      return `<span class="phase-item${activeClass}" title="${phaseLabels[p]}">${indicator}<span class="phase-label">${label}</span></span>`;
 340→    })
 341→    .join("");
 342→
 343→  const statusClass = getStatusClass(issue.status);
 344→  const statusText = issue.status.replace(/_/g, " ");
 345→  const title = escapeHtml(
 346→    issue.title.length > 50 ? issue.title.slice(0, 50) + "..." : issue.title,
 347→  );
 348→  const relativeTime = getRelativeTime(issue.lastActivity);
 349→
 350→  // Issue tracking age (AC-A6)
 351→  const trackingAge = formatTrackingAge(issue.createdAt);
 352→
 353→  let prInfo = "";
 354→  if (issue.pr) {
 355→    prInfo = `<a href="${escapeHtml(issue.pr.url)}" target="_blank" class="pr-link">PR #${issue.pr.number}</a>`;
 356→  }
 357→
 358→  let worktreeInfo = "";
 359→  if (issue.worktree) {
 360→    const shortPath =
 361→      issue.worktree.length > 40
 362→        ? "..." + issue.worktree.slice(-37)
 363→        : issue.worktree;
 364→    worktreeInfo = `<span class="worktree" title="${escapeHtml(issue.worktree)}">${escapeHtml(shortPath)}</span>`;
 365→  }
 366→
 367→  // Branch name with copy button (AC-A5)
 368→  let branchInfo = "";
 369→  if (issue.branch) {
 370→    const shortBranch =
 371→      issue.branch.length > 30 ? "..." + issue.branch.slice(-27) : issue.branch;
 372→    branchInfo = `<span class="branch-info">
 373→      <span class="branch-name" title="${escapeHtml(issue.branch)}">${escapeHtml(shortBranch)}</span>
 374→      <button class="copy-btn" onclick="copyToClipboard('${escapeHtml(issue.branch)}')" title="Copy branch name">📋</button>
 375→    </span>`;
 376→  }
 377→
 378→  // Acceptance Criteria section (AC-B4)
 379→  const acSection = renderACSection(issue.acceptanceCriteria);
 380→
 381→  return `
 382→    <article class="issue-card" data-issue="${issue.number}" data-status="${issue.status}">
 383→      <header>
 384→        <h3>#${issue.number}: ${title}</h3>
 385→        <span class="status-badge ${statusClass}">${statusText}</span>
 386→      </header>
 387→      <div class="phases">
 388→        ${phaseIndicators}
 389→      </div>
 390→      ${acSection}
 391→      <footer>
 392→        <div class="meta">
 393→          ${prInfo}
 394→          ${branchInfo}
 395→          ${worktreeInfo}
 396→        </div>
 397→        <div class="timestamps">
 398→          <small class="tracking-age">${trackingAge}</small>
 399→          <small class="last-activity">${relativeTime}</small>
 400→        </div>
 401→      </footer>
 402→    </article>
 403→  `;
 404→}
