 406→/**
 407→ * Render the issues list partial
 408→ */
 409→function renderIssuesList(issues: IssueState[]): string {
 410→  if (issues.length === 0) {
 411→    return `
 412→      <div class="empty-state">
 413→        <p>No issues being tracked.</p>
 414→        <p><small>Run <code>sequant run &lt;issue&gt;</code> to start tracking.</small></p>
 415→      </div>
 416→    `;
 417→  }
 418→
 419→  // Group by status
 420→  const byStatus: Record<IssueStatus, IssueState[]> = {
 421→    in_progress: [],
 422→    waiting_for_qa_gate: [],
 423→    ready_for_merge: [],
 424→    blocked: [],
 425→    not_started: [],
 426→    merged: [],
 427→    abandoned: [],
 428→  };
 429→
 430→  for (const issue of issues) {
 431→    byStatus[issue.status].push(issue);
 432→  }
 433→
 434→  // Sort each group by last activity
 435→  for (const status of Object.keys(byStatus) as IssueStatus[]) {
 436→    byStatus[status].sort(
 437→      (a, b) =>
 438→        new Date(b.lastActivity).getTime() - new Date(a.lastActivity).getTime(),
 439→    );
 440→  }
 441→
 442→  // Render in priority order
 443→  const statusOrder: IssueStatus[] = [
 444→    "in_progress",
 445→    "waiting_for_qa_gate",
 446→    "ready_for_merge",
 447→    "blocked",
 448→    "not_started",
 449→    "merged",
 450→    "abandoned",
 451→  ];
 452→
 453→  let html = '<div class="issues-grid">';
 454→  for (const status of statusOrder) {
 455→    for (const issue of byStatus[status]) {
 456→      html += renderIssueCard(issue);
 457→    }
 458→  }
 459→  html += "</div>";
 460→
 461→  // Summary stats
 462→  const total = issues.length;
 463→  const inProgress = byStatus.in_progress.length;
 464→  const qaGate = byStatus.waiting_for_qa_gate.length;
 465→  const ready = byStatus.ready_for_merge.length;
 466→  const blocked = byStatus.blocked.length;
 467→
 468→  html += `
 469→    <div class="summary">
 470→      <span>Total: ${total}</span>
 471→      ${inProgress > 0 ? `<span class="stat primary">In Progress: ${inProgress}</span>` : ""}
 472→      ${qaGate > 0 ? `<span class="stat warning">QA Gate: ${qaGate}</span>` : ""}
