 878→/**
 879→ * Create the Hono app
 880→ */
 881→export function createApp(stateManager: StateManager): Hono {
 882→  const app = new Hono();
 883→
 884→  // Main page
 885→  app.get("/", (c) => {
 886→    return c.html(renderMainPage());
 887→  });
 888→
 889→  // Issues list partial (for htmx)
 890→  app.get("/issues", async (c) => {
 891→    try {
 892→      // Clear cache to ensure fresh state on every request
 893→      stateManager.clearCache();
 894→      const allIssues = await stateManager.getAllIssueStates();
 895→      const issues = Object.values(allIssues);
 896→      return c.html(renderIssuesList(issues));
 897→    } catch (error) {
 898→      return c.html(
 899→        `<div class="empty-state"><p>Error loading state: ${escapeHtml(String(error))}</p></div>`,
 900→      );
 901→    }
 902→  });
 903→
 904→  // SSE endpoint for live updates
 905→  app.get("/events", async (c) => {
 906→    return streamSSE(c, async (stream) => {
 907→      let isActive = true;
 908→      let messageId = 0;
 909→
 910→      // Callback to receive broadcast updates
 911→      const onUpdate = (html: string) => {
 912→        if (isActive) {
 913→          stream
 914→            .writeSSE({
 915→              data: html.replace(/\n/g, ""),
 916→              event: "issues-update",
 917→              id: String(messageId++),
 918→            })
 919→            .catch(() => {
 920→              isActive = false;
 921→            });
 922→        }
 923→      };
 924→
 925→      // Register client
 926→      clients.add(onUpdate);
 927→
 928→      // Handle client disconnect
 929→      stream.onAbort(() => {
 930→        isActive = false;
 931→        clients.delete(onUpdate);
 932→      });
 933→
 934→      // Send initial data
 935→      try {
 936→        // Clear cache to ensure fresh state for new SSE connections
 937→        stateManager.clearCache();
 938→        const allIssues = await stateManager.getAllIssueStates();
 939→        const issues = Object.values(allIssues);
 940→        const html = renderIssuesList(issues);
 941→        await stream.writeSSE({
 942→          data: html.replace(/\n/g, ""),
 943→          event: "issues-update",
 944→          id: String(messageId++),
 945→        });
 946→      } catch {
 947→        // Ignore initial load errors
 948→      }
 949→
 950→      // Keep connection alive with heartbeat
 951→      while (isActive) {
 952→        await stream.sleep(30000);
 953→      }
 954→
 955→      // Cleanup
 956→      clients.delete(onUpdate);
 957→    });
 958→  });
 959→
 960→  // Health check
 961→  app.get("/health", (c) => {
 962→    return c.json({ status: "ok", clients: clients.size });
 963→  });
 964→
 965→  return app;
 966→}
 967→
 968→/**
 969→ * Broadcast update to all connected SSE clients
 970→ */
 971→async function broadcastUpdate(stateManager: StateManager): Promise<void> {
 972→  if (clients.size === 0) return;
 973→
 974→  try {
 975→    // Clear cache to get fresh state
 976→    stateManager.clearCache();
 977→    const allIssues = await stateManager.getAllIssueStates();
 978→    const issues = Object.values(allIssues);
 979→    const html = renderIssuesList(issues);
 980→
 981→    // Notify all connected clients
 982→    for (const callback of clients) {
 983→      try {
 984→        callback(html);
 985→      } catch {
 986→        // Client callback failed, will be cleaned up on disconnect
 987→      }
 988→    }
 989→  } catch {
 990→    // Ignore broadcast errors
 991→  }
 992→}
 993→
 994→/**
 995→ * Start the dashboard server
 996→ */
 997→export async function startDashboard(
 998→  options: DashboardOptions = {},
 999→): Promise<{ close: () => void }> {
1000→  const port = options.port ?? 3456;
1001→  const shouldOpen = options.open ?? true;
1002→  const statePath = options.statePath ?? STATE_FILE_PATH;
1003→  const verbose = options.verbose ?? false;
1004→
1005→  const stateManager = new StateManager({ statePath, verbose });
1006→  const app = createApp(stateManager);
1007→
1008→  // Set up file watcher for state changes
1009→  let watcher: ReturnType<typeof watch> | null = null;
1010→
1011→  // Ensure parent directory exists for watching
1012→  const stateDir = statePath.includes("/")
1013→    ? statePath.slice(0, statePath.lastIndexOf("/"))
1014→    : ".sequant";
1015→
1016→  if (!fs.existsSync(stateDir)) {
1017→    fs.mkdirSync(stateDir, { recursive: true });
1018→  }
1019→
1020→  watcher = watch(statePath, {
1021→    ignoreInitial: true,
1022→    awaitWriteFinish: {
1023→      stabilityThreshold: 100,
1024→      pollInterval: 50,
1025→    },
1026→  });
1027→
1028→  watcher.on("change", () => {
1029→    if (verbose) {
1030→      console.log("📊 State file changed, broadcasting update...");
1031→    }
1032→    broadcastUpdate(stateManager);
1033→  });
1034→
1035→  watcher.on("add", () => {
1036→    if (verbose) {
1037→      console.log("📊 State file created, broadcasting update...");
1038→    }
1039→    broadcastUpdate(stateManager);
1040→  });
1041→
1042→  // Start server
1043→  const server = serve({
1044→    fetch: app.fetch,
1045→    port,
1046→  });
1047→
1048→  const url = `http://localhost:${port}`;
1049→  console.log(`\n🚀 Sequant Dashboard running at ${url}\n`);
1050→
1051→  // Open browser
1052→  if (shouldOpen) {
1053→    const openModule = await import("open");
1054→    await openModule.default(url);
1055→  }
1056→
1057→  return {
1058→    close: () => {
1059→      if (watcher) {
1060→        watcher.close();
1061→      }
1062→      server.close();
1063→      console.log("\n👋 Dashboard server stopped\n");
1064→    },
1065→  };
1066→}
1067→
1068→// CLI entry point when run directly
1069→if (import.meta.url === `file://${process.argv[1]}`) {
1070→  const args = process.argv.slice(2);
1071→  const port = args.includes("--port")
1072→    ? parseInt(args[args.indexOf("--port") + 1], 10)
1073→    : 3456;
1074→  const noOpen = args.includes("--no-open");
1075→  const verbose = args.includes("--verbose");
1076→
1077→  startDashboard({ port, open: !noOpen, verbose }).catch((error) => {
1078→    console.error("Failed to start dashboard:", error);
1079→    process.exit(1);
1080→  });
1081→}
